import React from "react";
import { useNavigate } from "react-router-dom";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";

function ResultPage() {
  const navigate = useNavigate();
  const result = JSON.parse(localStorage.getItem("prediction_result"));
  const user = JSON.parse(localStorage.getItem("user"));

  if (!result) {
    return (
      <div className="dashboard-layout">
        <Sidebar role="patient" />
        <div className="main-content">
          <Navbar title="Prediction Result" subtitle="No result found" />
          <div className="empty-card">
            <h4>No Prediction Result Available</h4>
            <p>Please submit symptoms first.</p>
          </div>
        </div>
      </div>
    );
  }

  const handleBookAppointment = () => {
    navigate("/appointments");
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="patient" />

      <div className="main-content">
        <Navbar
          title="Prediction Result"
          subtitle="AI-generated medical recommendation"
        />

        <div className="result-card">
          <h2>{result.predicted_disease}</h2>
          <p className="result-subtitle">
            Recommended Specialist: <strong>{result.specialization}</strong>
          </p>

          <div className="result-grid">
            <div className="result-box">
              <h5>Patient Name</h5>
              <p>{result.patient_name || user?.name}</p>
            </div>

            <div className="result-box">
              <h5>Doctor Name</h5>
              <p>{result.doctor_name}</p>
            </div>

            <div className="result-box">
              <h5>Confidence</h5>
              <p>{result.confidence}%</p>
            </div>

            <div className="result-box">
              <h5>Report ID</h5>
              <p>#{result.report_id}</p>
            </div>
          </div>

          <div className="mt-4 d-flex gap-3 flex-wrap">
            <button className="btn btn-premium" onClick={handleBookAppointment}>
              Book Appointment
            </button>

            <a
              href={`http://127.0.0.1:5000/generate-pdf/${result.report_id}`}
              className="btn btn-outline-primary"
              target="_blank"
              rel="noreferrer"
            >
              Download PDF
            </a>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ResultPage;
